from sklearn.svm import SVC
from sklearn.metrics import accuracy_score
import numpy as np

def solve(X_train, y_train, X_val, y_val):
    # Define a range of hyperparameters to try for each model type
    param_grid = {
        'SVC': {
            'C': [0.1, 1, 10],
            'kernel': ['linear', 'rbf'],
            'gamma': ['scale', 'auto']
        }
    }

    best_accuracy = 0.9295
    best_params = {}

    # Iterate over the hyperparameter grid for each model type
    for model_type, params in param_grid.items():
        if model_type == 'SVC':
            for C in params['C']:
                for kernel in params['kernel']:
                    for gamma in params['gamma']:
                        clf = SVC(C=C, kernel=kernel, gamma=gamma)
                        clf.fit(X_train, y_train)
                        predictions = clf.predict(X_val)
                        accuracy = accuracy_score(y_val, predictions)

                        if accuracy > best_accuracy:
                            best_accuracy = accuracy
                            best_params[model_type] = {
                                'C': C,
                                'kernel': kernel,
                                'gamma': gamma
                            }

    # Train the final model with the best parameters for each model type
    models = []
    for model_type, params in best_params.items():
        clf = SVC(**params)
        clf.fit(X_train, y_train)
        models.append((model_type, clf))

    # Create a VotingClassifier to aggregate predictions
    voting_clf = VotingClassifier(estimators=models, voting='hard')
    voting_clf.fit(X_train, y_train)

    # Make predictions on validation set
    predictions = voting_clf.predict(X_val)
    return np.array(predictions)

